spec_artefacts.jsonschema:
{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://example.com/schemas/QuoteResponse.json",
  "type": "object",
  "required": ["quote", "author"],
  "properties": {
    "quote": {
      "type": "string",
      "description": "The full text of the quote retrieved from the Quote-of-the-Day API."
    },
    "author": {
      "type": ["string", "null"],
      "description": "The attributed author of the quote, or null if the source API does not supply an author. [implied]"
    }
  },
  "additionalProperties": false
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://example.com/schemas/JokeResponse.json",
  "type": "object",
  "required": ["joke"],
  "properties": {
    "joke": {
      "type": "string",
      "description": "The full text of the joke as a single string, used for single-part joke payloads."
    },
    "setup": {
      "type": "string",
      "description": "The setup portion of a two-part joke. Present only when the Joke API returns a two-part structure. [implied]"
    },
    "punchline": {
      "type": "string",
      "description": "The punchline portion of a two-part joke. Present only when the Joke API returns a two-part structure. [implied]"
    }
  },
  "additionalProperties": false
}

{
  "$schema": "https://json-schema.org/draft/2020-12/schema",
  "$id": "https://example.com/schemas/ErrorResponse.json",
  "type": "object",
  "required": ["error", "retryable"],
  "properties": {
    "error": {
      "type": "string",
      "description": "A human-readable message describing the API failure, suitable for direct display to the user within the interface session."
    },
    "retryable": {
      "type": "boolean",
      "description": "Indicates whether the client should offer the user the option to retry the failed request. True when the failure condition is transient or otherwise recoverable by retrying."
    }
  },
  "additionalProperties": false
}

spec_artefacts.c4:
workspace "Quote and Joke Application" "C4 architecture model for the Next.js 14 quote-of-the-day and joke application." {

    model {

        anonymousUser = person "Anonymous End User" "A person who accesses the application without authentication to receive time-based greetings and retrieve quote or joke content."

        nextjsApp = softwareSystem "Next.js Application" "A Next.js 14 application deployed on Vercel or Docker that serves a React browser client and exposes API routes proxying to third-party content APIs." {

            reactBundle = container "React Browser Bundle" "Renders the time-based greeting derived from the client device clock, presents content selection options, and displays retrieved quote or joke text." "React 18 / Next.js 14 App Router" "Browser"

            apiRoutes = container "Next.js API Routes" "Server-side route handlers that receive content requests from the React browser bundle and proxy them to the appropriate third-party external API." "Next.js 14 Route Handlers (Node.js)" "Server"

        }

        quoteApi = softwareSystem "Quote-of-the-Day API" "Third-party external API that returns a single quote-of-the-day text response upon request." "External"

        jokeApi = softwareSystem "Joke API" "Third-party external API that returns a single joke text response upon request." "External"

        # Relationships — Person to System
        anonymousUser -> reactBundle "Opens application, selects content option, and views time-based greeting and returned text content via browser UI."

        # Relationships — Container to Container
        reactBundle -> apiRoutes "Sends content retrieval request identifying the selected option (quote or joke) over HTTPS fetch." [implied]

        # Relationships — Container to External Systems
        apiRoutes -> quoteApi "Proxies quote retrieval request and receives single quote text response over HTTPS when user selects quote option."
        apiRoutes -> jokeApi "Proxies joke retrieval request and receives single joke text response over HTTPS when user selects joke option."

    }

    views {

        systemContext nextjsApp "SystemContext" "C4 System Context diagram showing the Next.js application, its users, and the external APIs it depends upon." {
            include *
            autoLayout lr
        }

        container nextjsApp "Containers" "C4 Container diagram showing the React browser bundle and Next.js API routes within the Next.js application boundary and their relationships to external systems." {
            include *
            autoLayout lr
        }

        styles {

            element "Person" {
                shape Person
                background #08427B
                color #ffffff
            }

            element "Software System" {
                background #1168BD
                color #ffffff
            }

            element "External" {
                background #999999
                color #ffffff
            }

            element "Container" {
                background #438DD5
                color #ffffff
            }

            element "Browser" {
                shape WebBrowser
                background #438DD5
                color #ffffff
            }

            element "Server" {
                shape RoundedBox
                background #2E6DA4
                color #ffffff
            }

            relationship "Relationship" {
                dashed false
                color #707070
            }

        }

    }

}
